export function initialize(dotNetRef, element, timeoutMs) {
    let timerId = null;
    let isIdle = false;

    const events = ['mousemove', 'keydown', 'click', 'scroll', 'touchstart'];

    function onActivity() {
        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync('OnUserActive');
        }
        resetTimer();
    }

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }
        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync('OnUserIdle');
        }, timeoutMs);
    }

    for (const evt of events) {
        element.addEventListener(evt, onActivity, { passive: true });
    }

    resetTimer();

    return {
        dispose() {
            if (timerId !== null) {
                clearTimeout(timerId);
                timerId = null;
            }
            for (const evt of events) {
                element.removeEventListener(evt, onActivity);
            }
        }
    };
}

